/** Realistic widget background images (resized JPEG data URIs) */

const IMG_CLARA = "data:image/jpeg;base64,";

const IMG_MIND = "data:image/jpeg;base64,";

const IMG_SLEEP = "data:image/jpeg;base64,";

const IMG_MEDS = "data:image/jpeg;base64,";

const IMG_TODAY = "data:image/jpeg;base64,";

export const WIDGET_IMAGES = {
  clara: IMG_CLARA,
  mind: IMG_MIND,
  sleep: IMG_SLEEP,
  meds: IMG_MEDS,
  today: IMG_TODAY,
} as const;

export type WidgetImageKey = keyof typeof WIDGET_IMAGES;

export function widgetImageUrl(key: WidgetImageKey): string {
  return WIDGET_IMAGES[key];
}
